// embed-semantic-link.mjs — generate lib/notebook/loom-semantic-link-preamble.ts
// from lib/notebook/loom-semantic-link.py so the notebook session preamble has a
// single source of truth (the .py file, which is ALSO the AML compute-instance
// PYTHONPATH module). Run from apps/fiab-console:
//   node scripts/embed-semantic-link.mjs
//
// Next.js server bundles can't reliably read a sibling .py at runtime, so we
// embed it as a string constant the BFF imports. Re-run whenever the .py
// changes; CI can `git diff --exit-code` the generated file to catch drift.
import { readFileSync, writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const pyPath = join(here, '..', 'lib', 'notebook', 'loom-semantic-link.py');
const outPath = join(here, '..', 'lib', 'notebook', 'loom-semantic-link-preamble.ts');

const py = readFileSync(pyPath, 'utf8');
const escaped = py.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');

const out = `// GENERATED by scripts/embed-semantic-link.mjs — DO NOT EDIT BY HAND.
// Source of truth: lib/notebook/loom-semantic-link.py
//
// LOOM_SEMANTIC_LINK_PREAMBLE is injected as a notebook session statement so
// LoomDataFrame / read_table / evaluate_measure / validate_relationships are
// available with no pip install (FGC-17). Azure-native, no Fabric / Power BI.
/* eslint-disable */
export const LOOM_SEMANTIC_LINK_PREAMBLE: string = \`${escaped}\`;
`;

writeFileSync(outPath, out, 'utf8');
console.log(`wrote ${outPath} (${py.length} bytes of python embedded)`);
